export function addValidation(){document.getElementById("demo-container").innerHTML='\n    <form class="row g-3 needs-validation" novalidate>\n      <div class="col-md-4">\n        <label for="validationCustom01" class="form-label">First name</label>\n        <input type="text" class="form-control" id="validationCustom01" value="Mark" required>\n        <div class="valid-feedback">\n          Looks good!\n        </div>\n      </div>\n      <div class="col-md-4">\n        <label for="validationCustom02" class="form-label">Last name</label>\n        <input type="text" class="form-control" id="validationCustom02" value="Otto" required>\n        <div class="valid-feedback">\n          Looks good!\n        </div>\n      </div>\n      <div class="col-md-4">\n        <label for="validationCustomUsername" class="form-label">Username</label>\n        <div class="input-group has-validation">\n          <span class="input-group-text" id="inputGroupPrepend">@</span>\n          <input type="text" class="form-control" id="validationCustomUsername" aria-describedby="inputGroupPrepend" required>\n          <div class="invalid-feedback">\n            Please choose a username.\n          </div>\n        </div>\n      </div>\n      <div class="col-md-6">\n        <label for="validationCustom03" class="form-label">City</label>\n        <input type="text" class="form-control" id="validationCustom03" required>\n        <div class="invalid-feedback">\n          Please provide a valid city.\n        </div>\n      </div>\n      <div class="col-md-3">\n        <label for="validationCustom04" class="form-label">State</label>\n        <select class="form-select" id="validationCustom04" required>\n          <option selected disabled value="">Choose...</option>\n          <option>...</option>\n        </select>\n        <div class="invalid-feedback">\n          Please select a valid state.\n        </div>\n      </div>\n      <div class="col-md-3">\n        <label for="validationCustom05" class="form-label">Zip</label>\n        <input type="text" class="form-control" id="validationCustom05" required>\n        <div class="invalid-feedback">\n          Please provide a valid zip.\n        </div>\n      </div>\n      <div class="col-12">\n        <div class="form-check">\n          <input class="form-check-input" type="checkbox" value="" id="invalidCheck" required>\n          <label class="form-check-label" for="invalidCheck">\n            Agree to terms and conditions\n          </label>\n          <div class="invalid-feedback">\n            You must agree before submitting.\n          </div>\n        </div>\n      </div>\n      <div class="col-12">\n        <button class="btn btn-primary" type="submit">Submit form</button>\n      </div>\n    </form>\n  ',(()=>{"use strict";const forms=document.querySelectorAll(".needs-validation");Array.from(forms).forEach((form=>{form.addEventListener("submit",(event=>{form.checkValidity()||(event.preventDefault(),event.stopPropagation()),form.classList.add("was-validated")}),!1)}))})(),setTooltips()}